// 1. Lấy text từ AI Agent (hỗ trợ nhiều định dạng output của n8n)
const input = items[0].json;
let rawText = input.output || 
              input.text || 
              input.response || 
              (input.content && input.content.parts ? input.content.parts[0].text : "") ||
              (input.message && input.message.content ? input.message.content : "");

try {
  // 2. Dùng Regex bóc tách đúng cụm JSON { ... }
  const jsonMatch = rawText.match(/\{[\s\S]*\}/);
  if (!jsonMatch) throw new Error("Không tìm thấy JSON trong phản hồi của AI");

  const parsed = JSON.parse(jsonMatch[0]);

  // 3. Ép cấu trúc đầu ra chuẩn nhưng giữ nguyên dữ liệu từ AI
  // Nếu AI không trả về field đó, sẽ để là null thay vì giá trị mặc định sai lệch
  return [{
    json: {
      category: parsed.category || null,
      brand: parsed.brand || null,
      model_slug: parsed.model_slug || null,
      status: typeof parsed.status === "boolean" ? parsed.status : false
    }
  }];

} catch (e) {
  // 4. Trường hợp lỗi format hoàn toàn, trả về object rỗng đúng cấu trúc
  return [{
    json: {
      category: "ERROR_FORMAT",
      brand: null,
      model_slug: null,
      status: false,
      raw_debug: rawText.substring(0, 100) // Để bạn dễ kiểm tra AI đang trả ra cái gì
    }
  }];
}

// 1. Lấy dữ liệu output từ node Router phía trước
const d = $input.first().json;
const base = 'https://raw.githubusercontent.com/Meeyana/thacoauto-lib/main/';

// Chuẩn hóa dữ liệu (Viết thường, bỏ dấu cách thừa để khớp với tên file trên Github)
const brand = (d.brand || "").toLowerCase().trim();
const model_slug = (d.model_slug || "").toLowerCase().trim();

let files = [];
let need_more_info = false; // Cờ báo hiệu thiếu thông tin

// ==========================================
// 2. LOGIC PHÂN LUỒNG DỰA TRÊN THÔNG TIN
// ==========================================

// Case 1: Không có thông tin gì hết (Trống cả brand và model)
if (!brand && !model_slug) {
    need_more_info = true;
} 
// Case 2: Chỉ có Brand (vd: "Tư vấn xe Kia")
else if (brand && !model_slug) {
    files.push(`wiki/brands/${brand}.md`);
} 
// Case 3: Đã có Model cụ thể (vd: "Carens")
else if (model_slug) {
    let final_slug = model_slug;

    // Auto-fix: Nếu slug chưa có tên brand (carens), mà brand có (kia) -> ghép lại thành "kia-carens"
    if (brand && !model_slug.startsWith(brand)) {
        final_slug = `${brand}-${model_slug}`;
    }

    files.push(`wiki/models/${final_slug}.md`);
}

// ==========================================
// 3. THỰC HIỆN TRUY VẤN FILE TỪ GITHUB
// ==========================================
let bundle = '';

// Nếu không bị thiếu thông tin thì mới đi kéo file
if (!need_more_info && files.length > 0) {
    for (const f of files) {
        try {
            // Hàm httpRequest của n8n để gọi GET data từ link
            const data = await this.helpers.httpRequest({ 
                method: 'GET', 
                url: base + f, 
                returnFullResponse: false 
            });
            bundle += `\n\n=== TÀI LIỆU DỮ LIỆU: ${f} ===\n${typeof data === 'string' ? data : JSON.stringify(data)}`;
        } catch (e) { 
            // Nếu link Github bị lỗi 404 (Không có file)
            bundle += `\n\n=== TÀI LIỆU: ${f} ===\n[HỆ THỐNG BÁO LỖI: Hiện chưa có tài liệu cho dòng xe này trên hệ thống. Vui lòng báo khách chờ hoặc hỏi thông tin khác]`; 
        }
    }
} else {
    bundle = "[HỆ THỐNG BÁO LỖI: Thiếu thông tin thương hiệu hoặc dòng xe. Yêu cầu AI hỏi lại khách hàng xem họ quan tâm xe nào.]";
}

// ==========================================
// 4. TRẢ KẾT QUẢ CHO NODE AI TIẾP THEO
// ==========================================
return [{ 
    json: { 
        ...d,                 // Giữ nguyên category, brand, model_slug cũ
        need_more_info: need_more_info, 
        files_used: files, 
        context_bundle: bundle // ĐÂY CHÍNH LÀ NỘI DUNG FILE MARKDOWN
    } 
}];

